tool.command:
exec 3>&1 4>&2;
exec > enzywizard.log 2>&1;

MSMS_EXE=\$(command -v msms || command -v msms.x86_64Linux2.2.6.1 || true);
if [ -n "\$MSMS_EXE" ]; then mkdir -p "\$HOME"; echo "set pyvol_msms_exe, \$MSMS_EXE" > "\$HOME/.pymolrc"; fi;

mkdir -p tmp; export TMPDIR="\$PWD/tmp"; export TEMP="\$TMPDIR"; export TMP="\$TMPDIR"; export QT_QPA_PLATFORM=offscreen; export LIBGL_ALWAYS_SOFTWARE=1; export PYOPENGL_PLATFORM=osmesa;
mkdir -p python_compat;
printf '%s\n' 'import sys, types, io' 'try:' '    import numpy as np' '    if not hasattr(np, "float_"): np.float_ = np.float64' 'except Exception: pass' 'm = types.ModuleType("rdkit.six")' 'm.StringIO = io.StringIO' 'sys.modules.setdefault("rdkit.six", m)' 'try:' '    import rdkit; setattr(rdkit, "six", m)' 'except Exception: pass' > python_compat/sitecustomize.py;
export PYTHONPATH="\$PWD/python_compat\${PYTHONPATH:+:\$PYTHONPATH}";
ORIG_MK_PREPARE_RECEPTOR=\$(command -v mk_prepare_receptor.py || true);
mkdir -p bin_compat;
printf '%s\n' '#!/usr/bin/env bash' 'real="\${ENZYWIZARD_REAL_MK_PREPARE_RECEPTOR:-}"' 'if [ -z "\$real" ] || [ ! -x "\$real" ]; then echo "Original mk_prepare_receptor.py not found" >&2; exit 127; fi' 'old=0' 'inp=""' 'out=""' 'args=("\$@")' 'i=0' 'while [ "\$i" -lt "\$#" ]; do' '  case "\${args[\$i]}" in' '    --read_pdb) old=1; i=\$((i+1)); inp="\${args[\$i]}" ;;' '    --write_pdbqt) old=1; i=\$((i+1)); out="\${args[\$i]}" ;;' '    --allow_bad_res) ;;' '    --delete_residues) i=\$((i+1)) ;;' '  esac' '  i=\$((i+1))' 'done' 'if [ "\$old" = 1 ]; then' '  if [ -z "\$inp" ] || [ -z "\$out" ]; then echo "Compatibility wrapper requires --read_pdb and --write_pdbqt" >&2; exit 2; fi' '  base="\${out%.pdbqt}"' '  "\$real" --pdb "\$inp" -o "\$base" --skip_gpf' '  rc=\$?' '  if [ "\$rc" -ne 0 ]; then exit "\$rc"; fi' '  if [ -s "\$base.pdbqt" ]; then cp -f "\$base.pdbqt" "\$out"; exit 0; fi' '  if [ -s "\${base}_rigid.pdbqt" ]; then cp -f "\${base}_rigid.pdbqt" "\$out"; exit 0; fi' '  if [ -s "\$out" ]; then exit 0; fi' '  echo "Compatibility wrapper did not find generated PDBQT for base \$base" >&2; exit 1' 'fi' 'exec "\$real" "\$@"' > bin_compat/mk_prepare_receptor.py;
chmod +x bin_compat/mk_prepare_receptor.py;
export ENZYWIZARD_REAL_MK_PREPARE_RECEPTOR="\$ORIG_MK_PREPARE_RECEPTOR";
export PATH="\$PWD/bin_compat:\$PATH";
echo "REAL_MK_PREPARE_RECEPTOR=\${ORIG_MK_PREPARE_RECEPTOR:-not found}" >&4;
echo "MSMS_EXE=\${MSMS_EXE:-not found}" >&4; command -v pymol >&4 2>&4 || true; command -v mk_prepare_receptor.py >&4 2>&4 || true; command -v enzywizard-dock >&4 2>&4 || true; python -c 'import importlib.util, os, sys, numpy as np; print("HOME=", os.environ.get("HOME")); print("QT_QPA_PLATFORM=", os.environ.get("QT_QPA_PLATFORM")); print("pymol module=", bool(importlib.util.find_spec("pymol"))); print("pyvol module=", bool(importlib.util.find_spec("pyvol"))); print("numpy float_ shim=", hasattr(np, "float_")); print("rdkit.six shim=", "rdkit.six" in sys.modules)' >&4 2>&4 || true;

#set $input_name = $input_path.element_identifier
ln -s '$input_path' '$input_name' &&
mkdir -p substrate_dir_raw substrate_dir &&
unzip -q '$substrate_zip' -d substrate_dir_raw &&
find substrate_dir_raw -type f \( -iname '*.sdf' \) -exec cp -L {} substrate_dir/ \; &&
python -c 'import sys,pathlib; from Bio.PDB import MMCIFParser,PDBParser,PDBIO; p=pathlib.Path(sys.argv[1]); parser=MMCIFParser(QUIET=True) if p.suffix.lower() in [".cif",".mmcif"] else PDBParser(QUIET=True); s=parser.get_structure("diag", str(p)); io=PDBIO(); io.set_structure(s); io.save("diag_receptor.pdb")' '$input_name' > diag_convert.stdout 2> diag_convert.stderr || true;
if [ -s diag_receptor.pdb ]; then mk_prepare_receptor.py --read_pdb diag_receptor.pdb --write_pdbqt diag_receptor.pdbqt --allow_bad_res > mk_prepare_receptor_diag.stdout 2> mk_prepare_receptor_diag.stderr || true; fi;
echo "---- mk_prepare_receptor diagnostic ----" >&4; [ -f diag_convert.stderr ] && cat diag_convert.stderr >&4; [ -f mk_prepare_receptor_diag.stdout ] && cat mk_prepare_receptor_diag.stdout >&4; [ -f mk_prepare_receptor_diag.stderr ] && cat mk_prepare_receptor_diag.stderr >&4; [ -s diag_receptor.pdbqt ] && echo "diag_receptor.pdbqt created" >&4;
enzywizard-dock
-i '$input_name'
-s '$substrate_names'
-d substrate_dir
-o ./
--max_docking_attempt_num '$advanced.max_docking_attempt_num'
$advanced.no_early_stop
--exhaustiveness '$advanced.exhaustiveness'
--cpu "\${GALAXY_SLOTS:-1}"
--min_rad '$advanced.min_rad'
--max_rad '$advanced.max_rad'
--min_volume '$advanced.min_volume'
#if $advanced.catalytic_residue:
--catalytic_residue '$advanced.catalytic_residue'
#end if
#if $advanced.catalytic_site_coord:
--catalytic_site_coord '$advanced.catalytic_site_coord'
#end if
#if $advanced.box_size:
--box_size '$advanced.box_size'
#end if
;
status=\$?;
echo "---- files in Galaxy job working directory ----" >&4;
find . -maxdepth 4 -type f | sort >&4;
if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi;
if ! find . -maxdepth 2 -type f \( -name 'dock_report*.json' -o -name 'docked*.cif' -o -name 'docked*.pdb' -o -name 'docked*.sdf' \) | grep -q .; then echo "No EnzyWizard Dock output files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
